  const visibleTasks=useMemo(()=>(tasks||[]).filter(canSeeTask),[tasks,canSeeTask]);
  const computed=useMemo(()=>visibleTasks.map(t=>({...t,status:getStatus(t)})),[visibleTasks]);
  const stats=useMemo(()=>computed.reduce((a,t)=>({...a,total:a.total+1,[t.status]:a[t.status]+1}),{total:0,on_time:0,nearly_due:0,overdue:0,completed:0}),[computed]);
  const deptChart=useMemo(()=>DEPTS.map(d=>{const dt=computed.filter(t=>t.dept===d);return{name:d,"Trong hạn":dt.filter(t=>t.status==="on_time").length,"Sắp hết hạn":dt.filter(t=>t.status==="nearly_due").length,"Quá hạn":dt.filter(t=>t.status==="overdue").length,"Hoàn thành":dt.filter(t=>t.status==="completed").length};}), [computed]);
  const filtered=useMemo(()=>{const f=computed.filter(t=>{if(fStatus!=="all"&&t.status!==fStatus)return false;if(fDept!=="all"&&t.dept!==fDept)return false;if(fEid!=="all"&&t.eid!==fEid)return false;if(search&&!t.title.toLowerCase().includes(search.toLowerCase()))return false;return true;});if(fSort==="urgency")return[...f].sort((a,b)=>(STATUS_ORDER[a.status]??9)-(STATUS_ORDER[b.status]??9));if(fSort==="deadline_asc")return[...f].sort((a,b)=>a.deadline.localeCompare(b.deadline));if(fSort==="deadline_desc")return[...f].sort((a,b)=>b.deadline.localeCompare(a.deadline));if(fSort==="newest")return[...f].sort((a,b)=>(b.created||"").localeCompare(a.created||""));return f;},[computed,fStatus,fDept,fEid,search,fSort]);
  const calTasks=useMemo(()=>computed.filter(t=>{const d=new Date(t.deadline);return d.getFullYear()===calYear&&d.getMonth()===calMonth;}),[computed,calYear,calMonth]);
  const calTasksByDay=useMemo(()=>{const m={};calTasks.forEach(t=>{const day=new Date(t.deadline).getDate();if(!m[day])m[day]=[];m[day].push(t);});return m;},[calTasks]);
  const daysInMonth=new Date(calYear,calMonth+1,0).getDate();
  const firstDay=new Date(calYear,calMonth,1).getDay();
  const repTasks=useMemo(()=>computed.filter(t=>{const d=new Date(t.deadline);return d.getFullYear()===repYear&&d.getMonth()===repMonth;}),[computed,repYear,repMonth]);
  const repStats=useMemo(()=>{const total=repTasks.length,done=repTasks.filter(t=>t.status==="completed").length,over=repTasks.filter(t=>t.status==="overdue").length;return{total,done,over,rate:total?Math.round(done/total*100):0};},[repTasks]);
  const repDeptData=useMemo(()=>DEPTS.map(d=>{const dt=repTasks.filter(t=>t.dept===d);const done=dt.filter(t=>t.status==="completed").length;return{name:d,total:dt.length,done,over:dt.filter(t=>t.status==="overdue").length,rate:dt.length?Math.round(done/dt.length*100):0};}), [repTasks]);
  const repEmpData=useMemo(()=>(employees||[]).map(emp=>{const et=repTasks.filter(t=>t.eid===emp.id);const done=et.filter(t=>t.status==="completed").length,over=et.filter(t=>t.status==="overdue").length;return{...emp,total:et.length,done,over,rate:et.length?Math.round(done/et.length*100):0};}).filter(e=>e.total>0).sort((a,b)=>b.rate-a.rate),[employees,repTasks]);
  const repMonthTrend=useMemo(()=>{const months=[];for(let i=5;i>=0;i--){const d=new Date(repYear,repMonth-i,1);const m=d.getMonth(),y=d.getFullYear();const mt=computed.filter(t=>{const td=new Date(t.deadline);return td.getFullYear()===y&&td.getMonth()===m;});months.push({name:`T${m+1}`,done:mt.filter(t=>t.status==="completed").length,total:mt.length});}return months;},[computed,repYear,repMonth]);
  const leaderboard=useMemo(()=>{const yt=computed.filter(t=>{const d=new Date(t.created||t.deadline);return d.getFullYear()===rankYear;});return(employees||[]).map(emp=>{const et=yt.filter(t=>t.eid===emp.id);const done=et.filter(t=>t.completed);const over=et.filter(t=>t.status==="overdue");const tot=done.filter(t=>t.rating==="tot").length,dat=done.filter(t=>t.rating==="dat").length,cd=done.filter(t=>t.rating==="chua_dat").length,unrated=done.filter(t=>!t.rating).length;return{...emp,total:et.length,done:done.length,over:over.length,tot,dat,cd,unrated,score:tot*3+dat*2-over.length,rate:et.length?Math.round(done.length/et.length*100):0};}).filter(e=>e.total>0).sort((a,b)=>b.score-a.score||b.rate-a.rate);},[computed,employees,rankYear]);
  const lateReasonStats=useMemo(()=>{const lt=computed.filter(t=>t.late_reason);const total=lt.length;return LATE_REASONS.map(r=>({...r,count:lt.filter(t=>t.late_reason===r.value).length,pct:total?Math.round(lt.filter(t=>t.late_reason===r.value).length/total*100):0})).filter(r=>r.count>0).sort((a,b)=>b.count-a.count);},[computed]);
  const overloadedEmps=useMemo(()=>(employees||[]).map(emp=>{const active=computed.filter(t=>t.eid===emp.id&&!t.completed);return{...emp,activeCount:active.length};}).filter(e=>e.activeCount>=overloadThreshold),[employees,computed,overloadThreshold]);
  const notifications=useMemo(()=>computed.filter(t=>t.status==="overdue"||t.status==="nearly_due").sort((a,b)=>(STATUS_ORDER[a.status]??9)-(STATUS_ORDER[b.status]??9)),[computed]);
  const myTasks=useMemo(()=>{if(!currentUser?.employee_id)return null;const my=computed.filter(t=>t.eid===currentUser.employee_id||parseJSON(t.collab_eids,[]).includes(currentUser.employee_id));const done=my.filter(t=>t.completed).length,over=my.filter(t=>t.status==="overdue").length,nd=my.filter(t=>t.status==="nearly_due").length,active=my.filter(t=>!t.completed);return{total:my.length,done,over,nd,rate:my.length?Math.round(done/my.length*100):0,pending:active.sort((a,b)=>(STATUS_ORDER[a.status]??9)-(STATUS_ORDER[b.status]??9)).slice(0,3)};},[computed,currentUser]);

